// ─── Run ─────────────────────────────────────────────────────────────────────
async function seed() {
  console.log('🌱 Seeding SlushFund database...\n');

  // Clear existing awards
  console.log('Clearing existing awards...');
  await supabase.from('awards').delete().neq('id', '0000').then(() => {});

  // Clear tax_expenditures
  console.log('Clearing existing tax expenditures...');
  await supabase.from('tax_expenditures').delete().neq('id', '0000').then(() => {});

  // Insert political entities
  console.log(`Seeding ${POLITICAL_ENTITIES.length} political entities...`);
  const { error: entitiesError } = await supabase.from('political_entities').insert(POLITICAL_ENTITIES);
  if (entitiesError) {
    console.error('Political entities error:', entitiesError.message);
  } else {
    console.log('✓ Political entities seeded');
  }

  // Insert awards
  const contracts = AWARDS.filter(a => a.award_category === 'contract').length;
  const grants = AWARDS.filter(a => a.award_category === 'grant').length;
  const loans = AWARDS.filter(a => a.award_category === 'loan').length;
  console.log(`Seeding ${AWARDS.length} awards (${contracts} contracts, ${grants} grants, ${loans} loans)...`);

  let successCount = 0;
  for (const award of AWARDS) {
    const { error } = await supabase.from('awards').insert(award);
    if (error) {
      console.error(`Failed [${award.award_id}]: ${error.message}`);
    } else {
      successCount++;
    }
  }
  console.log(`✓ Seeded ${successCount}/${AWARDS.length} awards`);

  // Insert tax expenditures
  console.log(`Seeding ${TAX_EXPENDITURES.length} tax expenditures...`);
  let teCount = 0;
  for (const te of TAX_EXPENDITURES) {
    const { error } = await supabase.from('tax_expenditures').insert(te);
    if (error) {
      console.error(`Failed tax expenditure [${te.id}]: ${error.message}`);
    } else {
      teCount++;
    }
  }
  console.log(`✓ Seeded ${teCount}/${TAX_EXPENDITURES.length} tax expenditures`);

  // Verify
  const { count: awardCount } = await supabase.from('awards').select('*', { count: 'exact', head: true });
  const { count: entityCount } = await supabase.from('political_entities').select('*', { count: 'exact', head: true });
  const { count: teActualCount } = await supabase.from('tax_expenditures').select('*', { count: 'exact', head: true });

  console.log(`\n✅ Seed complete!`);
  console.log(`   Awards: ${awardCount ?? successCount}`);
  console.log(`   Political entities: ${entityCount ?? POLITICAL_ENTITIES.length}`);
  console.log(`   Tax expenditures: ${teActualCount ?? teCount}`);
}

seed().catch(e => { console.error(e); process.exit(1); });
